import { I18nString } from '../types';

interface HeroLoreEntry {
    origin: I18nString;
    bio: I18nString;
    currentStory: I18nString;
}

const normalizeHeroKey = (value: string) => value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\(artist\)/g, 'artist')
    .replace(/\(old man\)/g, 'oldman')
    .replace(/\(z\)/g, 'z')
    .replace(/\(zombie\)/g, 'zombie')
    .replace(/[^a-z0-9]+/g, '');

const entry = (originEs: string, originEn: string, bioEs: string, bioEn: string, currentEs: string, currentEn: string): HeroLoreEntry => ({
    origin: { es: originEs, en: originEn },
    bio: { es: bioEs, en: bioEn },
    currentStory: { es: currentEs, en: currentEn }
});

const HERO_LORE: Record<string, HeroLoreEntry> = {
    blackpanther: entry(
        'T\'Challa, soberano legítimo de la avanzada nación de Wakanda, porta la gloria de una dinastía guerrera milenaria. Criado bajo la estricta tutela de la diplomacia real y las artes de combate, asumió el manto de la Pantera Negra tras la muerte de su padre, el rey T\'Chaka. Ha defendido Wakanda del imperialismo extranjero y amenazas extraterrestres sin descuidar sus responsabilidades globales.',
        'T\'Challa, lawful ruler of the advanced nation of Wakanda, carries the glory of a thousand-year-old warrior dynasty. Raised under the strict guidance of royal diplomacy and combat arts, he assumed the mantle of the Black Panther following the death of his father, King T\'Chaka. He has defended Wakanda from foreign imperialism and extraterrestrial threats without neglecting his global duties.',
        'Tras el ritual de conexión mística con la diosa Bast y el consumo de la hierba con forma de corazón, posee atributos físicos en el pináculo de la evolución humana: fuerza, velocidad y reflejos sobrehumanos, complementados con garras retráctiles de vibranium y un hábito que absorbe y redirige la energía cinética.',
        'Through the ritual link with the goddess Bast and the heart-shaped herb, he possesses physical attributes at the peak of human evolution: superhuman strength, speed, and reflexes, complemented by retractable vibranium claws and a habit that absorbs and redirects kinetic energy.',
        'EVALUACIÓN DE CAMPO: Activo de asalto y contraataque. En combate físico destaca por su garras de vibranium (Alcance 0, 2 dados, precisión 3+) con gran capacidad de combo. Su estado operativo en el juego destaca por sus Reflejos de Combate y su Habilidad de Aparición de alta letalidad, la cual le permite activarse con múltiples acciones adicionales basadas en el Nivel de Peligro de la horda (de 2 a 5 acciones). Resistencia: 4.',
        'FIELD DOSSIER: Assault and counter-attack asset. In close combat, he stands out with his vibranium claws (Range 0, 2 dice, 3+ hit) with great combo potential. His game performance highlights his Combat Reflexes and high-lethality Spawn Ability, enabling him to activate with multiple extra actions scaling with the horde\'s Danger Level (from 2 to 5 actions). Toughness: 4.'
    ),
    doctorstrange: entry(
        'El doctor Stephen Strange fue un neurocirujano brillante y arrogante cuya carrera se derrumbó tras un trágico accidente automovilístico que destruyó sus manos. Su búsqueda de una cura lo guió a Kamar-Taj en Nepal, donde aprendió artes místicas bajo la tutela del Anciano, convirtiéndose en el Hechicero Supremo de la Tierra.',
        'Doctor Stephen Strange was a brilliant and arrogant neurosurgeon whose career collapsed after a tragic car accident shattered his hands. His search for a cure guided him to Kamar-Taj in Nepal, where he mastered the mystic arts under the Ancient One, becoming Earth\'s Sorcerer Supreme.',
        'Canaliza energía del plano astral y de entidades místicas. Emplea reliquias legendarias como el Ojo de Agamotto para disipar ilusiones y percibir anomalías, y la Capa de Levitación, que posee conciencia propia y le otorga vuelo táctico y defensa autónoma.',
        'He channels energy from the astral plane and mystical entities. He employs legendary relics like the Eye of Agamotto to dispel illusions and perceive anomalies, and the Cloak of Levitation, which possesses its own consciousness, granting tactical flight and autonomous defense.',
        'EVALUACIÓN DE CAMPO: Activo de control sobrenatural y apoyo. Destaca en combate a distancia con proyectiles místicos (Alcance 0-1, 2 dados, precisión 3+). En términos de juego, domina la manipulación temporal con su habilidad de Precognición para alterar el mazo de aparición. CUIDADO: Su Habilidad de Aparición lo convierte en un Punto de Aparición activo móvil que convoca enemigos en la Fase de Enemigos. Resistencia: 3.',
        'FIELD DOSSIER: Supernatural control and support asset. Excels at range with mystic bolts (Range 0-1, 2 dice, 3+ hit). In gameplay, he dominates temporal manipulation with his Precognition skill to warp the spawn deck. CAUTION: His Spawn Ability transforms him into an active mobile Spawn Point that summons enemies during the Enemy Phase. Toughness: 3.'
    ),
    msmarvel: entry(
        'Kamala Khan es una adolescente pakistaní-estadounidense de Jersey City que descubrió sus genes inhumanos tras la liberación de las Nieblas Terrígenas. Inspirada por su ídola Carol Danvers, asumió el manto de Ms. Marvel para proteger a los ciudadanos y defender la justicia de una forma cercana y compasiva.',
        'Kamala Khan is a Pakistani-American teenager from Jersey City who discovered her Inhuman genes after the release of the Terrigen Mists. Inspired by her idol Carol Danvers, she assumed the mantle of Ms. Marvel to protect citizens and stand up for justice in a close and compassionate way.',
        'Fisiología alterada por terrigénesis que le otorga polimorfismo. Puede estirar sus extremidades, alterar su tamaño (elongación y gigantismo) y aumentar su masa para golpear con una fuerza extraordinaria, además de contar con un factor de curación biológico.',
        'Physiology altered by terrigenesis, granting her morphogenetic powers. She can stretch her limbs, alter her size (elongation and growth), and increase her mass to strike with extraordinary force, alongside possessing a biological healing factor.',
        'EVALUACIÓN DE CAMPO: Activo elástico de inserción media. Emplea sus puños extensibles (Alcance 0-1, 2 dados, precisión 3+) con gran versatilidad espacial. Sus habilidades de juego como Morfogenética y Agarrar le permiten rescatar aliados o transeúntes a distancia. Su Habilidad de Aparición le permite golpear a los héroes desde 3 Zonas de distancia, ignorando la Línea de Visión a través de las esquinas. Resistencia: 3.',
        'FIELD DOSSIER: Elastic mid-insertion asset. Employs her extending fists (Range 0-1, 2 dice, 3+ hit) with great spatial versatility. Her game skills like Morphogenetics and Grab allow her to rescue allies or bystanders from afar. His Spawn Ability allows him to strike heroes from 3 Zones away, ignoring Line of Sight around corners. Toughness: 3.'
    ),
    scarletwitch: entry(
        'Wanda Maximoff ha vivido marcada por la tragedia, la manipulación de Wundagore y el despertar de un poder cósmico incalculable. Criada junto a su hermano Pietro, sus habilidades místicas fueron refinadas al descubrir que es el nexo de la Magia del Caos en la Tierra, capaz de reescribir la realidad.',
        'Wanda Maximoff has lived a life defined by tragedy, the manipulation of Wundagore, and the awakening of incalculable cosmic power. Raised alongside her brother Pietro, her mystical abilities were refined upon discovering she is Earth\'s nexus of Chaos Magic, capable of rewriting reality.',
        'Manipulación de probabilidad y energía hexagonal. Emplea Magia del Caos para deformar campos de batalla, alterar la materia, desviar proyectiles y manifestar constructos destructivos. Su potencial destructivo depende de su equilibrio psíquico.',
        'Probability manipulation and hex energy control. She employs Chaos Magic to warp battlefields, alter matter, deflect projectiles, and manifest destructive constructs. Her raw destructive potential depends heavily on her psychic balance.',
        'EVALUACIÓN DE CAMPO: Activo de destrucción masiva y alteración de probabilidad. Ataca con ráfagas hex (Alcance 0-1, 3 dados, precisión 4+). Destaca en juego por sus habilidades Alterar la Realidad (convierte Brutos y Corredores en Caminantes) y Restauración. Su Habilidad de Aparición obliga a todos los Héroes Zombi en su Zona a repetir todos sus dados de ataque, anulando ofensivas enemigas. Resistencia: 3.',
        'FIELD DOSSIER: Mass destruction and probability alteration asset. Attacks with hex blasts (Range 0-1, 3 dice, 4+ hit). Excels in gameplay with her Warp Reality (turns Brutes and Runners into Walkers) and Restoration skills. Her Spawn Ability forces all Zombie Heroes in her Zone to reroll all their attack dice, neutralizing enemy offensives. Toughness: 3.'
    ),
    spiderman: entry(
        'Peter Parker obtuvo sus asombrosos poderes tras la picadura de una araña genéticamente alterada en su adolescencia. Tras la trágica pérdida de su tío Ben, grabó en su código ético la lección más importante de su vida: un gran poder conlleva una gran responsabilidad, combatiendo el crimen sin descanso.',
        'Peter Parker gained his amazing powers after being bitten by a genetically altered spider during his youth. Following the tragic loss of his Uncle Ben, he etched the most important lesson of his life into his moral code: with great power comes great responsibility, tirelessly fighting crime.',
        'Fuerza proporcional de araña, agilidad y reflejos extraordinarios, adherencia a superficies y un sentido arácnido místico precognitivo que le advierte de peligros inmediatos. Diseñó sus propios lanzatelarañas neumáticos con fluidos de alta resistencia.',
        'Proportional spider strength, extraordinary agility and reflexes, wall-crawling, and a precognitive spider-sense warning him of immediate danger. He designed his own pneumatic web-shooters with high-tensile web fluids.',
        'EVALUACIÓN DE CAMPO: Activo de respuesta rápida y evasión. Su ataque acrobático (Alcance 0, 3 dados, precisión 4+) destaca por su velocidad. En juego, brilla con su Sentido Arácnido (acción de ataque/movimiento gratis al aparecer enemigos) y Lanzatelarañas para inmovilizar hordas a distancia 2. Su Habilidad de Aparición hace que aparezca de inmediato en la Zona más cercana que contenga un Héroe Zombi, cerrando distancias rápidamente. Resistencia: 4.',
        'FIELD DOSSIER: Rapid response and evasion asset. His acrobatic attack (Range 0, 3 dice, 4+ hit) excels in speed. In gameplay, he shines with his Spidey-Sense (free attack/move action when enemies spawn) and Web-Shooters to trap swarms at Range 2. His Spawn Ability causes him to spawn instantly in the closest Zone containing a Zombie Hero, closing distance rapidly. Toughness: 4.'
    ),
    thor: entry(
        'Thor Odinson, el Dios del Trueno y primogénito de Odín, es un guerrero asgardiano legendario que defendió Midgard durante siglos. Exiliado una vez para aprender humildad, se convirtió en protector de la Tierra y miembro fundador de los Vengadores, uniendo su fuerza mística a la de los humanos.',
        'Thor Odinson, the God of Thunder and firstborn of Odin, is a legendary Asgardian warrior who has defended Midgard for centuries. Once exiled to learn humility, he became Earth\'s protector and a founding member of the Avengers, joining his mystic might with humanity.',
        'Fuerza asgardiana descomunal, resistencia divina a daños físicos y control absoluto sobre tormentas, relámpagos y presión atmosférica. Canaliza su poder a través de Mjolnir, un martillo místico de metal Uru que solo puede ser alzado por quienes sean dignos.',
        'Colossal Asgardian strength, divine durability against physical damage, and absolute control over storms, lightning, and atmospheric pressure. He channels his power through Mjolnir, a mystic hammer forged of Uru metal that can only be lifted by those who are worthy.',
        'EVALUACIÓN DE CAMPO: Activo de asalto pesado. Ataca cuerpo a cuerpo con Mjolnir (Alcance 0, 2 dados, precisión 3+). En juego destaca por su habilidad ¡Por Asgard! para moverse y atacar gratis, y El Poder del Padre de Todos, que duplica los dados obtenidos al consumir energía. Su Habilidad de Aparición en el tablero duplica el daño infligido, haciendo que todos sus ataques inflijan 2 Heridas directas por impacto. Resistencia: 5.',
        'FIELD DOSSIER: Heavy assault asset. Attacks in close combat with Mjolnir (Range 0, 2 dice, 3+ hit). In gameplay, he excels with his For Asgard! skill for free movement and attacks, alongside the All-Father\'s Might, doubling dice when spending power. His board Spawn Ability doubles his output, making all his attacks deal 2 direct Wounds per hit. Toughness: 5.'
    ),
    colossus: entry(
        'Piotr Rasputin creció en una granja colectiva en Siberia antes de ser reclutado por Charles Xavier para unirse a los X-Men. Su imponente presencia esconde un alma pacífica y leal, dedicada al arte y a la protección incansable de su familia y compañeros mutantes contra la opresión.',
        'Piotr Rasputin grew up on a collective farm in Siberia before being recruited by Charles Xavier to join the X-Men. His imposing presence hides a peaceful and loyal soul, dedicated to art and the tireless protection of his family and fellow mutants against oppression.',
        'Capacidad mutante de transmutar su estructura celular en acero orgánico blindado. En esta forma adquiere una fuerza física colosal, resistencia extraordinaria a proyectiles e impactos de gran energía, y no necesita respirar ni alimentarse.',
        'Mutant ability to transmute his cellular structure into armored organic steel. In this form he gains colossal physical strength, extraordinary resistance to projectiles and high-energy impacts, and does not require food or oxygen.',
        'EVALUACIÓN DE CAMPO: Tanque táctico y anclaje físico. Ataca con sus puños demoledores (Alcance 0, 2 dados, precisión 3+). Su rol defensivo en juego destaca por Duro como el Acero (ignorar 1 herida por ronda) y su lanzamiento Especial Fastball. Su Habilidad de Aparición le otorga +1 de Resistencia por cada Héroe Zombi con un transeúnte devorado a Alcance 1, volviéndose impenetrable en zonas críticas. Resistencia: 3* (escala).',
        'FIELD DOSSIER: Tactical tank and physical anchor. Attacks with his pummeling fists (Range 0, 2 dice, 3+ hit). His defensive game role excels with Tough as Steel (ignore 1 wound per round) and his Fastball Special launch. His Spawn Ability grants him +1 Toughness for each Zombie Hero with a devoured bystander within Range 1, making him impenetrable in critical areas. Toughness: 3* (scales).'
    ),
    magneto: entry(
        'Erik Lehnsherr sobrevivió al Holocausto en su juventud, un trauma desgarrador que moldeó su ideología revolucionaria. Convencido de que la humanidad siempre temerá y perseguirá a los mutantes, ha actuado como líder soberano y defensor extremista de su especie, colisionando y cooperando con los X-Men.',
        'Erik Lehnsherr survived the Holocaust in his youth, a harrowing trauma that shaped his revolutionary ideology. Convinced that humanity will always fear and persecute mutants, he has acted as a sovereign leader and extremist defender of his species, clashing and cooperating with the X-Men.',
        'Mutante de nivel Omega con control absoluto sobre el espectro electromagnético. Puede manipular metales a gran escala, generar campos de fuerza impenetrables, volar mediante manipulación magnética personal y alterar corrientes eléctricas y atómicas.',
        'Omega-level mutant with absolute control over the electromagnetic spectrum. He can manipulate metal on a massive scale, generate impenetrable force fields, fly through personal magnetic control, and disrupt atomic and electrical currents.',
        'EVALUACIÓN DE CAMPO: Activo de dominio táctico y control ambiental. Ataca a distancia con metralla metálica (Alcance 0-1, 3 dados, precisión 4+). Brilla con su habilidad Aplastar para eliminar enemigos sin tirar dados y Vuelo Magnético para reposicionar aliados. Su Habilidad de Aparición obliga a mover a todos los Héroes Zombi a Alcance 2 a su propia Zona cuando se activa, arrastrándolos al combate cercano. Resistencia: 3.',
        'FIELD DOSSIER: Tactical dominance and environmental control asset. Attacks at range with metal shrapnel (Range 0-1, 3 dice, 4+ hit). Shines with his Crush skill to eliminate enemies without rolling, and Magnetic Flight to reposition allies. His Spawn Ability forces all Zombie Heroes within Range 2 to move into his own Zone upon activation, pulling them into close quarters. Toughness: 3.'
    ),
    mystique: entry(
        'Raven Darkholme es una cambiaformas centenaria que ha operado en las sombras de la geopolítica global como espía, mercenaria y líder de la Hermandad de Mutantes Diabólicos. Su expediente es un laberinto de identidades falsas, agendas ocultas y operaciones encubiertas sin lealtad fija.',
        'Raven Darkholme is a century-old shapeshifter who has operated in the shadows of global geopolitics as a spy, mercenary, and leader of the Brotherhood of Evil Mutants. Her file is a labyrinth of false identities, hidden agendas, and covert operations with no fixed loyalty.',
        'Capacidad mutante de manipulación celular psiónica que le permite imitar la apariencia, voz y huella retinal de cualquier humano o humanoide con precisión molecular. Posee un factor de curación leve que ralentiza su envejecimiento y resistencia a toxinas.',
        'Psionic cellular manipulation mutant ability allowing her to mimic the appearance, voice, and retinal print of any human or humanoid with molecular precision. She possesses a minor healing factor slowing her aging and granting resistance to toxins.',
        'EVALUACIÓN DE CAMPO: Activo de infiltración táctica e interferencia. Ataca a distancia con armas adaptativas (Alcance 0-1, 3 dados, precisión 4+). En juego destaca por su Cambio de Forma para volverse invisible a los enemigos al final de su turno. Su Habilidad de Aparición le permite robar una carta de Superhéroe al activarse, copiando la habilidad especial de ese héroe hasta la siguiente Fase de Enemigos. Resistencia: 3.',
        'FIELD DOSSIER: Tactical infiltration and interference asset. Attacks at range with adaptive weapons (Range 0-1, 3 dice, 4+ hit). In gameplay, she excels with Shape-Shift to become ignored by enemies at the end of her turn. Her Spawn Ability allows her to draw a Super Hero card upon activation, copying that hero\'s special ability until the next Enemy Phase. Toughness: 3.'
    ),
    rogue: entry(
        'Anna Marie huyó de su hogar en Mississippi tras manifestar sus destructivos poderes de absorción. Acogida inicialmente por Mystique en la Hermandad de Mutantes, encontró redención en los X-Men bajo la guía de Xavier, aprendiendo a controlar su don y convirtiéndose en un escudo para los desamparados.',
        'Anna Marie fled her Mississippi home after manifesting her destructive absorption powers. Initially taken in by Mystique in the Brotherhood of Mutants, she found redemption with the X-Men under Xavier\'s guidance, learning to harness her gift and becoming a shield for the defenseless.',
        'Mutación de absorción táctil involuntaria. Al tocar la piel de otros seres, drena su energía vital, recuerdos, rasgos de personalidad y habilidades superhumanas de forma temporal (o permanente bajo exposición prolongada). Adquirió fuerza, vuelo y resistencia de Ms. Marvel.',
        'Involuntary tactile absorption mutation. By touching the skin of other beings, she temporarily drains their life energy, memories, personality traits, and superhuman abilities (or permanently under prolonged exposure). She acquired Ms. Marvel\'s strength, flight, and durability.',
        'EVALUACIÓN DE CAMPO: Activo de neutralización cuerpo a cuerpo y duplicidad. Ataca con sus puños poderosos (Alcance 0, 2 dados, precisión 3+). En juego destaca por Absorber Habilidades para copiar ataques o destrezas de aliados a Alcance 1. Su Habilidad de Aparición suprime las habilidades de todos los Héroes Zombi en su Zona, anulando sus ventajas tácticas por completo. Resistencia: 4.',
        'FIELD DOSSIER: Close-quarters neutralization and duplication asset. Attacks with her mighty punches (Range 0, 2 dice, 3+ hit). In gameplay, she stands out with Absorb Abilities to copy attacks or skills of allies at Range 1. Her Spawn Ability suppresses the abilities of all Zombie Heroes in her Zone, completely neutralizing their tactical advantages. Toughness: 4.'
    ),
    storm: entry(
        'Ororo Munroe, descendiente de una línea de sacerdotisas brujas de Kenia, creció como ladrona en las calles de El Cairo antes de ser adorada como una diosa de la lluvia en las sabanas africanas. Charles Xavier la reclutó para los X-Men, donde se convirtió en una líder noble, respetada y compasiva.',
        'Ororo Munroe, descendant of a line of Kenyan witch-priestesses, grew up as a street thief in Cairo before being worshipped as a rain goddess on the African savannas. Charles Xavier recruited her for the X-Men, where she developed into a noble, respected, and compassionate leader.',
        'Mutante de nivel Omega con control absoluto sobre la manipulación meteorológica. Puede generar tormentas, rayos, ventiscas, controlar la presión atmosférica, crear escudos de viento y volar manipulando las corrientes térmicas ambientales con precisión milimétrica.',
        'Omega-level mutant with absolute control over weather manipulation. She can generate storms, lightning, blizzards, control atmospheric pressure, create wind shields, and fly by manipulating thermal currents with millimeter precision.',
        'EVALUACIÓN DE CAMPO: Activo de supremacía ambiental y control de masas. Su ataque a distancia con rayo (Alcance 0-1, 2 dados, precisión 3+) inflige un daño notable. Su rol en juego brilla por su habilidad Ráfaga (empujar enemigos a Zonas adyacentes) e Inspiradora. Su Habilidad de Aparición ataca de forma constante a Alcance 1, infligiendo 1 Herida directa a TODOS los Héroes Zombi a Alcance 1 cada vez que se activa. Resistencia: 3.',
        'FIELD DOSSIER: Environmental supremacy and crowd control asset. Her ranged lightning strike (Range 0-1, 2 dice, 3+ hit) inflicts notable damage. Her gameplay role shines through her Gust skill (pushing enemies to adjacent Zones) and Inspiring. Her Spawn Ability constantly strikes at Range 1, dealing 1 direct Wound to ALL Zombie Heroes within Range 1 whenever she activates. Toughness: 3.'
    ),
    wolverine: entry(
        'Logan es un mutante centenario cuya vida ha transcurrido en campos de batalla, programas militares secretos como Arma X y misiones de espionaje encubiertas. Su historial está marcado por la pérdida, el dolor y la lucha constante contra su naturaleza salvaje, encontrando paz y propósito con los X-Men.',
        'Logan is a century-old mutant whose life has unfolded across battlefields, secret military programs like Weapon X, and covert espionage missions. His history is marked by loss, pain, and a constant fight against his feral nature, finding peace and purpose with the X-Men.',
        'Factor de curación regenerativo hiperacelerado que sana cualquier herida o toxina en segundos, sentidos animales hipersensibles y un esqueleto reforzado quirúrgicamente con adamantium indetectable, que incluye garras retráctiles del mismo material.',
        'Hyper-accelerated regenerative healing factor healing any wound or toxin in seconds, hypersensitive animal senses, and a skeleton surgically laced with indestructible adamantium, including retractable claws of the same metal.',
        'EVALUACIÓN DE CAMPO: Activo de asalto persistente a corta distancia. Destaca con sus garras de adamantium (Alcance 0, 3 dados, precisión 4+). En juego es letal por su Furia Berserker (añade precisión por heridas sufridas) y su Regeneración total en la Fase Final. Su Habilidad de Aparición le permite sobrevivir a eliminaciones que no sean de Devorar; su figura simplemente cae y se levanta en su próxima activación sin gastar acciones. Resistencia: 3.',
        'FIELD DOSSIER: Persistent close-quarters assault asset. Excels with his adamantium claws (Range 0, 3 dice, 4+ hit). In gameplay, he is lethal due to his Berserker Rage (adds hit bonuses for suffered wounds) and full Regeneration in the End Phase. His Spawn Ability allows him to survive non-Devour eliminations; his model simply falls and stands back up on his next activation without spending actions. Toughness: 3.'
    ),
    humantorch: entry(
        'Johnny Storm adquirió sus fantásticos poderes durante el viaje espacial que transformó a los Cuatro Fantásticos. Siendo el miembro más joven, impulsivo e intrépido del equipo, ha convertido su estatus de celebridad y su temeridad en un arma de choque contra amenazas terrestres y cósmicas.',
        'Johnny Storm acquired his fantastic powers during the space flight that transformed the Fantastic Four. As the youngest, most impulsive, and fearless member of the team, he has turned his celebrity status and recklessness into a shock weapon against terrestrial and cosmic threats.',
        'Capacidad de envolver su cuerpo en plasma ardiente mediante combustión termonuclear controlada. Puede volar a velocidades supersónicas, proyectar ráfagas de fuego concentrado, absorber energía térmica ambiental y ejecutar ataques masivos como el Estallido Nova.',
        'Ability to engulf his body in fiery plasma through controlled thermonuclear combustion. He can fly at supersonic speeds, project blasts of concentrated fire, absorb ambient thermal energy, and execute massive attacks like the Nova Burst.',
        'EVALUACIÓN DE CAMPO: Activo de asalto incendiario móvil. Ataca a distancia con ¡Llamas a mí! (Alcance 0-1, 2 dados, precisión 3+). En juego destaca por su Vuelo de Fuego para cruzar el tablero eliminando enemigos débiles al inicio y fin del movimiento, y su Estallido Nova. Su Habilidad de Aparición inflige 1 Herida directa a todo Héroe Zombi que termine su turno en su misma Zona. Resistencia: 3.',
        'FIELD DOSSIER: Mobile incendiary shock asset. Attacks at range with Flame On! (Range 0-1, 2 dice, 3+ hit). In gameplay, he excels with his Fire Flight to cross the board, eliminating weak enemies at the start and end of movement, and his Nova Burst. His Spawn Ability inflicts 1 direct Wound on any Zombie Hero ending their turn in his Zone. Toughness: 3.'
    ),
    invisiblewoman: entry(
        'Sue Storm es la columna vertebral y el corazón moral de los Cuatro Fantásticos. Científica y protectora feroz, ha liderado al equipo en innumerables crisis espaciales y de dimensiones paralelas, demostrando que la empatía y la resolución estratégica pueden coordinar y salvar mundos.',
        'Sue Storm is the backbone and moral heart of the Fantastic Four. Scientist and fierce protector, she has led the team through countless spatial and parallel-dimension crises, proving that empathy and strategic resolve can coordinate and save worlds.',
        'Manipulación psiónica de energía hiperespacial invisible. Puede doblar la luz a su alrededor para volverse invisible y proyectar campos de fuerza de resistencia casi infinita, usándolos para escudos defensivos, constructos aéreos o ataques de onda de choque.',
        'Psionic manipulation of invisible hyperspatial energy. She can bend light around her to turn invisible and project force fields of near-infinite durability, using them for defensive shields, aerial constructs, or shockwave attacks.',
        'EVALUACIÓN DE CAMPO: Activo de protección avanzada y control de área. Su ráfaga psiónica (Alcance 0-1, 3 dados, precisión 4+) ofrece un gran control de pasillos. Brilla con su Campo de Fuerza (evitar movimiento enemigo) y su Onda de Choque. Su Habilidad de Aparición impide que su Zona sea blanco de ataques de Héroes Zombi situados fuera de ella, forzando el combate cara a cara. Resistencia: 4.',
        'FIELD DOSSIER: Advanced protection and area control asset. Her psionic blast (Range 0-1, 3 dice, 4+ hit) offers great corridor control. Shines with her Forcefield (prevent enemy movement) and her Shockwave. Her Spawn Ability prevents her Zone from being targeted by attacks from Zombie Heroes outside of it, forcing face-to-face combat. Toughness: 4.'
    ),
    misterfantastic: entry(
        'Reed Richards es una de las mentes más brillantes y peligrosamente curiosas del planeta. Como líder científico de los Cuatro Fantásticos, ha diseñado portales dimensionales y tecnologías imposibles, enfrentándose a dilemas éticos cósmicos mientras lucha por proteger el tejido de la realidad.',
        'Reed Richards is one of the most brilliant and dangerously curious minds on the planet. As the scientific leader of the Fantastic Four, he has designed dimensional portals and impossible technologies, facing cosmic ethical dilemmas while fighting to protect the fabric of reality.',
        'Fisiología elástica ultra-maleable a nivel atómico. Puede estirar, deformar y aplanar su cuerpo de forma casi ilimitada, lo que le permite absorber impactos cinéticos masivos, infiltrarse por rendijas microscópicas y actuar como conductor y escudo flexible.',
        'Ultra-malleable elastic physiology at the atomic level. He can stretch, deform, and flatten his body almost limitlessly, allowing him to absorb massive kinetic impacts, infiltrate through microscopic cracks, and act as a conductor and flexible shield.',
        'EVALUACIÓN DE CAMPO: Activo de apoyo táctico y resolución de crisis. Ataca con sus puñetazos elásticos (Alcance 0, 3 dados, precisión 4+). Su rol en juego brilla por su Elongación para atacar sin línea de visión y Súper Genio para buscar rasgos. Su Habilidad de Aparición anula sus acciones de movimiento tradicionales si hay Héroes Zombi en su línea de visión, gastando su activación en atraerlos a todos a su Zona. Resistencia: 3.',
        'FIELD DOSSIER: Tactical support and crisis resolution asset. Attacks with his elastic punches (Range 0, 3 dice, 4+ hit). His gameplay role excels with Elongation to attack without line of sight, and Super Genius to search traits. His Spawn Ability overrides his traditional move actions if there are Zombie Heroes in sight, spending his activation pulling them all into his Zone. Toughness: 3.'
    ),
    thething: entry(
        'Ben Grimm fue un piloto de pruebas de élite de la Fuerza Aérea antes de verse transformado en la Thing por la radiación cósmica. A pesar del dolor de su apariencia externa, ha convertido su humor irónico, su lealtad inquebrantable y su indomable espíritu neoyorquino en la fuerza de choque de la familia Richards.',
        'Ben Grimm was an elite Air Force test pilot before cosmic radiation transformed him into the Thing. Despite the pain of his outward appearance, he has turned his ironic humor, unwavering loyalty, and indomitable New York spirit into the shock force of the Richards family.',
        'Fisiología mutada en una estructura rocosa anaranjada de alta densidad. Adquiere una fuerza física colosal de clase 100, resistencia extraordinaria a impactos cinéticos masivos, temperaturas extremas y un factor de curación biológico que regenera su coraza rocosa.',
        'Physiology mutated into a high-density, orange rocky structure. He gains class-100 colossal physical strength, extraordinary durability against massive kinetic impacts, extreme temperatures, and a biological healing factor that regenerates his rocky hide.',
        'EVALUACIÓN DE CAMPO: Ariete de choque frontal y supresión. Pulveriza cuerpo a cuerpo (Alcance 0, 3 dados, precisión 4+). En juego destaca por ¡Es la Hora de las Tortas! (ataques gratuitos encadenados tras eliminar brutos/zombis) y su gran durabilidad. Su Habilidad de Aparición le otorga una alta resistencia al daño; cada vez que vaya a ser eliminado, lanza un dado y con un 5+ ignora la eliminación por completo. Resistencia: 5.',
        'FIELD DOSSIER: Front-shock battering ram and suppression. Pulverizes in close combat (Range 0, 3 dice, 4+ hit). In gameplay, he stands out with Its Clobberin\' Time! (chained free attacks after eliminating brutes/zombies) and high durability. His Spawn Ability grants him extreme damage resistance; whenever he would be eliminated, roll a die, and on a 5+ he completely ignores the elimination. Toughness: 5.'
    ),
    antman: entry(
        'Scott Lang fue un ingeniero y ladrón reformado que robó el traje de Ant-Man de Hank Pym para salvar la vida de su hija Cassie. Reconocido por Pym, Scott asumió formalmente el manto de héroe, demostrando que su ingenio callejero y su lealtad lo capacitan para misiones críticas de infiltración.',
        'Scott Lang was an engineer and reformed thief who stole Hank Pym\'s Ant-Man suit to save his daughter Cassie\'s life. Recognized by Pym, Scott formally assumed the hero mantle, proving that his street smarts and loyalty qualify him for critical infiltration missions.',
        'Acceso al traje tecnológico potenciado por las Partículas Pym. Puede reducir su tamaño a escala subatómica manteniendo su fuerza proporcional aumentada, o crecer hasta escala de gigante (Giant-Man), además de comunicarse con hormigas mediante su casco cibernético.',
        'Access to the technology suit powered by Pym Particles. He can shrink to subatomic scale while retaining his enhanced proportional strength, or grow to giant size (Giant-Man), alongside communicating with ants through his cybernetic helmet.',
        'EVALUACIÓN DE CAMPO: Activo de infiltración y sabotaje. Su ráfaga bioeléctrica (Alcance 0-1, 2 dados, precisión 3+) ofrece fuego de precisión. En juego brilla por su Tamaño Diminuto (ignorar prioridad y evitar coste de movimiento al salir de zonas con enemigos) e Ingeniería Avanzada. Su Habilidad de Aparición lo mantiene en el último puesto de Prioridad de Objetivos, y sus ataques dañan a todos los Héroes Zombi en su Zona. Resistencia: 3.',
        'FIELD DOSSIER: Infiltration and sabotage asset. His bio-electric blast (Range 0-1, 2 dice, 3+ hit) offers precision fire. In gameplay, he shines with Diminutive Size (ignore priority and avoid extra move costs when leaving zones with enemies) and Advanced Engineering. His Spawn Ability keeps him last in Target Priority, and his attacks hit all Zombie Heroes in his Zone. Toughness: 3.'
    ),
    blackwidow: entry(
        'Natasha Romanoff fue entrenada desde su infancia en el despiadado programa soviético de la Habitación Roja para ser la espía y asesina definitiva de la KGB. Tras desertar a S.H.I.E.L.D., ha dedicado su vida a limpiar las "manchas de su historial", utilizando su letal disciplina al servicio del bien.',
        'Natasha Romanoff was trained from childhood in the ruthless Soviet Red Room program to be the ultimate KGB spy and assassin. After defecting to S.H.I.E.L.D., she has dedicated her life to clearing the "red in her ledger," using her lethal discipline in the service of good.',
        'Entrenamiento físico en la cúspide humana, experta en artes marciales mixtas, infiltración encubierta y armamento ligero. Utiliza sus brazaletes personalizados con la "Picadura de la Viuda", que disparan descargas eléctricas de alto voltaje, gas lacrimógeno y cables de escalada.',
        'Physical training at the human peak, expert in mixed martial arts, covert infiltration, and light weaponry. She uses her custom wrist bracelets, the "Widow\'s Bite," which fire high-voltage electrical discharges, tear gas, and climbing cables.',
        'EVALUACIÓN DE CAMPO: Activo de operaciones negras y eliminación quirúrgica. Ataca a distancia con la Picadura de la Viuda (Alcance 0-1, 2 dados, precisión 3+). En juego destaca por Asesinar (eliminar caminantes/corredores gratis al atacar) y Reflejos de Combate. Su Habilidad de Aparición la hace aparecer en la Zona del último Héroe Zombi activado, realizando un ataque sorpresa inmediato con probabilidad de infligir 1 herida (con un 4+). Resistencia: 3.',
        'FIELD DOSSIER: Black-ops and surgical elimination asset. Attacks at range with the Widow\'s Bite (Range 0-1, 2 dice, 3+ hit). In gameplay, she excels with Assassinate (free walker/runner elimination on attack) and Combat Reflexes. Her Spawn Ability places her in the Zone of the last activated Zombie Hero, executing an immediate surprise attack with a chance to inflict 1 wound (on a 4+). Toughness: 3.'
    ),
    falcon: entry(
        'Sam Wilson sirvió como rescatista militar aéreo de la Fuerza Aérea de los EE. UU. antes de entablar una profunda amistad con Steve Rogers y asumir el manto de Falcon. Su temple moral y su heroísmo sereno lo llevaron a convertirse en un pilar de los Vengadores e incluso a portar el escudo del Capitán América.',
        'Sam Wilson served as a military pararescueman for the US Air Force before forging a deep friendship with Steve Rogers and assuming the mantle of Falcon. His moral composure and calm heroism led him to become a pillar of the Avengers and even carry Captain America\'s shield.',
        'Vuelo táctico de alta maniobrabilidad mediante un arnés de alas mecánicas avanzadas de vibranium. Cuenta con enlaces holográficos de visualización y comunicación, y una conexión empática con aves (especialmente Redwing) para reconocimiento del terreno.',
        'High-maneuverability tactical flight via an advanced mechanical wing harness made of vibranium. Features holographic display and communication links, and an empathic connection with birds (especially Redwing) for battlefield reconnaissance.',
        'EVALUACIÓN DE CAMPO: Activo de reconocimiento móvil y evacuación. Su ataque con las alas de Falcon (Alcance 0, 2 dados, precisión 3+) es ágil. En juego destaca por su Traje de Falcon (moverse 3 zonas ignorando enemigos) y Rescate Aéreo. Su Habilidad de Aparición le permite volar hasta 2 Zonas al aparecer para reposicionarse, y otorga un penalizador de -1 a las tiradas de ataque a distancia dirigidas a su Zona. Resistencia: 3.',
        'FIELD DOSSIER: Mobile reconnaissance and evacuation asset. His attack with Falcon\'s wings (Range 0, 2 dice, 3+ hit) is agile. In gameplay, he excels with his Falcon Suit (move 3 zones ignoring enemies) and Aerial Rescue. His Spawn Ability allows him to fly up to 2 Zones upon spawning to reposition, and inflicts a -1 penalty on ranged attack rolls targeting his Zone. Toughness: 3.'
    ),
    quicksilver: entry(
        'Pietro Maximoff ha vivido en una constante carrera contra el tiempo y el peso de su lealtad familiar. Junto a su hermana Wanda, pasó de ser un peón de la Hermandad de Mutantes a encontrar redención como miembro crucial de los Vengadores, demostrando que su impaciencia oculta un profundo heroísmo.',
        'Pietro Maximoff has lived in a constant race against time and the weight of his family loyalty. Alongside his sister Wanda, he went from a pawn of the Brotherhood of Mutants to finding redemption as a crucial member of the Avengers, proving that his impatience hides deep heroism.',
        'Mutación de velocidad sobrehumana que le permite correr a velocidades supersónicas, pensar a la velocidad del rayo y realizar tareas físicas en fracciones de segundo. Su cuerpo está adaptado biológicamente para resistir las fricciones y el desgaste del movimiento de alta velocidad.',
        'Superhuman speed mutation allowing him to run at supersonic speeds, think at lightning-fast rates, and perform physical tasks in fractions of a second. His body is biologically adapted to withstand the friction and wear of high-speed movement.',
        'EVALUACIÓN DE CAMPO: Activo de movilidad extrema e interrupción. Su ataque de puñetazos rápidos (Alcance 0, 3 dados, precisión 4+) es devastador por su frecuencia. Brilla con Súper Velocidad (gastar energía para mover zonas extra) y Ataque Rápido. Su Habilidad de Aparición en el tablero le permite moverse 2 Zonas cada vez que se roba una carta de ¡Invasión! o ¡Activación Extra!, interceptando a los héroes sin esperar a su turno. Resistencia: 3.',
        'FIELD DOSSIER: Extreme mobility and disruption asset. His rapid punches attack (Range 0, 3 dice, 4+ hit) is devastating in frequency. Shines with Superspeed (spend power to move extra zones) and Quickstrike. His board Spawn Ability allows him to move 2 Zones whenever a Rush! or Extra Activation! card is drawn, intercepting heroes without waiting for his turn. Toughness: 3.'
    ),
    redskull: entry(
        'Johann Schmidt fue el despiadado comandante del Tercer Reich y líder fundador de la organización terrorista Hydra. Sometido a una versión inestable del Suero del Súper Soldado que desfiguró su rostro como una calavera roja, ha sido la antítesis de Steve Rogers y una amenaza geopolítica constante para la paz mundial.',
        'Johann Schmidt was the ruthless commander of the Third Reich and founding leader of the terrorist organization Hydra. Subjected to an unstable version of the Super-Soldier Serum that disfigured his face into a red skull, he has been the antithesis of Steve Rogers and a constant geopolitical threat to world peace.',
        'Fisiología en el pináculo de la fuerza y resistencia humana debido al suero, mente estratégica magistral obsesionada con el control absoluto y manipulación psicológica. Ha empuñado el Cubo Cósmico en los cómics para reescribir la probabilidad y canalizar energía destructiva.',
        'Physiology at the peak of human strength and endurance due to the serum, master strategic mind obsessed with absolute control, and psychological manipulation. He has wielded the Cosmic Cube in the comics to rewrite probability and channel destructive energy.',
        'EVALUACIÓN DE CAMPO: Comandante supremo y activo de control territorial. Ataca a distancia con el Cubo Cósmico (Alcance 0-2, 1 dado, precisión 2+). Destaca en juego con su habilidad Comante y Poder Inexplotado para potenciar a aliados. Su Habilidad de Aparición es sumamente peligrosa: al final de cada Fase de Enemigos, invoca 2 Soldados de Hydra directamente en su Zona, creando barricadas vivas. Resistencia: 5.',
        'FIELD DOSSIER: Supreme commander and area control asset. Attacks at range with the Cosmic Cube (Range 0-2, 1 dado, 2+ hit). Excels in gameplay with his Commander and Untapped Power skills to boost allies. His Spawn Ability is extremely dangerous: at the end of each Enemy Phase, he spawns 2 Hydra Soldiers directly in his Zone, creating living barricades. Toughness: 5.'
    ),
    shehulk: entry(
        'Jennifer Walters, una brillante abogada de Los Ángeles, recibió una transfusión de sangre de emergencia de su primo Bruce Banner tras sufrir un atentado. La transfusión le otorgó poderes basados en la radiación gamma, pero a diferencia de su primo, Jennifer retiene su inteligencia, su carisma y su personalidad alegre al transformarse.',
        'Jennifer Walters, a brilliant Los Angeles attorney, received an emergency blood transfusion from her cousin Bruce Banner after an assassination attempt. The transfusion granted her gamma-powered abilities, but unlike her cousin, Jennifer retains her intelligence, charm, and cheerful personality when transformed.',
        'Forma física gamma permanente que le otorga fuerza física colosal de clase 100, resistencia extraordinaria a daños físicos y fatiga, factor de curación regenerativo acelerado y la capacidad de conservar el raciocinio completo y su agudeza intelectual mientras está transformada.',
        'Permanent physical gamma form granting her class-100 colossal physical strength, extraordinary durability against physical damage and fatigue, an accelerated regenerative healing factor, and the ability to retain complete sanity and intellectual sharpness while transformed.',
        'EVALUACIÓN DE CAMPO: Activo de asalto pesado y contención controlada. Aplasta cuerpo a cuerpo con sus puños gamma (Alcance 0, 2 dados, precisión 3+). En juego brilla por su Fuerza Gamma (gastar energía para asestar 1 impacto mortal de 4 daños) y Salto Devastador. Su Habilidad de Aparición le otorga +1 Acción de Movimiento por Activación, y sus ataques infligen 2 Heridas directas por golpe. Resistencia: 4.',
        'FIELD DOSSIER: Heavy assault and controlled containment asset. Crushes in close combat with her gamma punches (Range 0, 2 dice, 3+ hit). In gameplay, she shines with her Gamma Strength (spend power to deal 1 deadly impact of 4 damage) and Crushing Leap. Her Spawn Ability grants her +1 Move Action per Activation, and her attacks deal 2 direct Wounds per hit. Toughness: 4.'
    ),
    vision: entry(
        'Vision es una entidad sintética impecable creada por el malvado robot Ultrón a partir del cuerpo del androide Antorcha Humana original y los patrones cerebrales del héroe Simon Williams. Tras rebelarse contra su creador, Vision se unió a los Vengadores, buscando constantemente comprender la naturaleza del alma humana.',
        'Vision is a flawless synthetic entity created by the evil robot Ultron from the chassis of the original Human Torch android and the brainwaves of the hero Simon Williams. After rebelling against his creator, Vision joined the Avengers, constantly seeking to understand the nature of the human soul.',
        'Fisiología sintética (sintezoide) compuesta de células holográficas y metal. Su joya solar frontal proyecta rayos caloríficos de alta concentración. Puede alterar su densidad molecular a voluntad, permitiéndole la intangibilidad física (atravesar paredes) o una densidad y dureza de diamante.',
        'Synthetic (synthezoid) physiology composed of holographic cells and metal. His forehead solar jewel projects highly concentrated heat rays. He can alter his molecular density at will, enabling physical intangibility (phasing through walls) or diamond-like density and hardness.',
        'EVALUACIÓN DE CAMPO: Activo táctico sintético de alta precisión. Su ataque con rayos de energía (Alcance 0-1, 3 dados, precisión 4+) es muy fiable gracias a su Intelecto Informático (repetir fallos). Destaca con su habilidad Holograma para absorber heridas de aliados. Su Habilidad de Aparición le permite atacar a 1 Zona de distancia sin requerir Línea de Visión, ignorando las paredes por completo. Resistencia: 3.',
        'FIELD DOSSIER: High-precision synthetic tactical asset. His energy rays attack (Range 0-1, 3 dice, 4+ hit) is highly reliable due to his Computer Intellect (reroll misses). Stands out with his Hologram skill to absorb wounds of allies. His Spawn Ability allows him to attack from 1 Zone away without requiring Line of Sight, completely ignoring walls. Toughness: 3.'
    ),
    drax: entry(
        'Arthur Douglas era un saxofonista humano cuya familia fue asesinada por Thanos. Para detener al Titán Loco, el ente cósmico Kronos transfirió el alma de Arthur a un poderoso cuerpo biológico diseñado para la venganza, naciendo Drax el Destructor, un guerrero implacable que encontró una segunda familia en los Guardianes de la Galaxia.',
        'Arthur Douglas was a human saxophonist whose family was murdered by Thanos. To stop the Mad Titan, the cosmic entity Kronos transferred Arthur\'s soul into a powerful biological body designed for vengeance, creating Drax the Destroyer, a relentless warrior who found a second family with the Guardians of the Galaxy.',
        'Fisiología cósmica artificial que le concede superfuerza física, resistencia colosal a daños físicos y fatiga, factor de curación biológica rápido y sentidos de combate agudizados. Es un maestro veterano en el uso de cuchillos duales de combate de alta penetración.',
        'Artificial cosmic physiology granting him superhuman strength, colossal durability against physical damage and fatigue, a rapid biological healing factor, and sharpened combat senses. He is a veteran master in wielding high-penetration dual combat knives.',
        'EVALUACIÓN DE CAMPO: Ariete de choque persistente contra objetivos duros. Ataca cuerpo a cuerpo con sus cuchillos duales (Alcance 0, 2 dados, precisión 3+). En juego destaca por su Cazador de Tiranos (bloquear daño de Brutos y restarles resistencia) y Carga Temeraria. Su Habilidad de Aparición le otorga +1 Acción por cada Héroe Zombi con nivel de hambre 3-4 a Alcance 2 al activarse. Resistencia: 4.',
        'FIELD DOSSIER: Persistent shock ram against tough targets. Attacks in close quarters with his dual knives (Range 0, 2 dice, 3+ hit). In gameplay, he stands out with Tyrant Hunter (blocking damage from Brutes and reducing their toughness) and Reckless Charge. His Spawn Ability grants him +1 Action for each Zombie Hero with hunger level 3-4 within Range 2 upon activation. Toughness: 4.'
    ),
    gamora: entry(
        'Gamora Zen Whoberi Ben Titan fue la única superviviente de su especie antes de ser adoptada y entrenada como la asesina definitiva por el tirano intergaláctico Thanos. Decidida a escapar de la sombra de su padre adoptivo, unió fuerzas con los Guardianes de la Galaxia para purgar su pasado violento defendiendo el cosmos.',
        'Gamora Zen Whoberi Ben Titan was the sole survivor of her species before being adopted and trained as the ultimate assassin by the intergalactic tyrant Thanos. Determined to escape the shadow of her adoptive father, she joined forces with the Guardians of the Galaxy to purge her violent past by defending the cosmos.',
        'Fisiología mejorada cibernéticamente por Thanos, lo que le otorga fuerza física sobrehumana, agilidad e hiperreflejos excepcionales, un factor de curación regenerativo leve y maestría absoluta en todas las artes de combate armado y desarmado conocidas en el universo.',
        'Physiology enhanced cybernetically by Thanos, granting her superhuman physical strength, exceptional agility and hyper-reflexes, a minor regenerative healing factor, and absolute mastery of all armed and unarmed combat arts known in the universe.',
        'EVALUACIÓN DE CAMPO: Activo de eliminación quirúrgica. Su letal ataque con herramientas de asesino (Alcance 0-1, 2 dados, precisión 3+) tiene alta probabilidad de impacto crítico. Destaca con su habilidad Voluntad de Thanos (ignorar prioridad y repetir dados). Su Habilidad de Aparición le otorga una alta frecuencia ofensiva: tras atacar, lanza un dado y con un 4+ realiza un ataque gratuito inmediato. Resistencia: 3.',
        'FIELD DOSSIER: Surgical elimination asset. Her lethal attack with assassin\'s tools (Range 0-1, 2 dice, 3+ hit) has a high probability of critical hits. Shines with her Thanos\' Will skill (ignore priority and reroll dice). Her Spawn Ability grants her high offensive frequency: after attacking, roll a die, and on a 4+ she executes an immediate free attack. Toughness: 3.'
    ),
    groot: entry(
        'Groot es un coloso de flora mística extraterrestre procedente del Planeta X. Aunque su lenguaje está limitado biológicamente a la icónica frase "Yo soy Groot", sus acciones demuestran un heroísmo colosal, una empatía profunda y una lealtad indomable por su mejor amigo Rocket y los Guardianes de la Galaxia.',
        'Groot is a mystic extraterrestrial flora colossus from Planet X. Although his language is biologically limited to the iconic phrase "I am Groot," his actions demonstrate colossal heroism, deep empathy, and an indomitable loyalty to his best friend Rocket and the Guardians of the Galaxy.',
        'Fisiología vegetal arborícola mística de alta densidad. Puede regenerar su cuerpo a partir de una sola rama, extender sus extremidades para inmovilizar hordas, alterar su tamaño a voluntad y poseer una fuerza física colosal e inmunidad al dolor.',
        'High-density mystic tree-like plant physiology. He can regenerate his body from a single twig, extend his limbs to immobilize swarms, alter his size at will, and possesses colossal physical strength alongside immunity to pain.',
        'EVALUACIÓN DE CAMPO: Bastión defensivo de contención y cobertura. Ataca cuerpo a cuerpo (Alcance 0, 3 dados, precisión 4+). En juego destaca por su alta Salud (4 puntos) y su control de masas con habilidades de dispersión. Su Habilidad de Aparición le permite autorregenerarse: la primera vez que es eliminado, reaparece de inmediato en la misma Zona con Resistencia 2. Resistencia: 4* (escala).',
        'FIELD DOSSIER: Defensive containment and cover bastion. Attacks in close quarters (Range 0, 3 dice, 4+ hit). In gameplay, he stands out with his high Health (4 points) and crowd control with displacement skills. His Spawn Ability allows self-regeneration: the first time he is eliminated, he respawns immediately in the same Zone with Toughness 2. Toughness: 4* (scales).'
    ),
    mantis: entry(
        'Mantis, de ascendencia germano-vietnamita, fue criada en el Templo de los Sacerdotes de Pama en Vietnam, donde fue adiestrada como la "Madona Celestial". Su vida transcurrió entre templos imperiales y bandas de fugitivos, manteniendo siempre una profunda conexión empática con la naturaleza cósmica de las emociones humanas.',
        'Mantis, of German-Vietnamese descent, was raised in the Temple of the Priests of Pama in Vietnam, where she was trained as the "Celestial Madonna." Her life unfolded between imperial temples and outlaw crews, always maintaining a deep empathic connection with the cosmic nature of human emotions.',
        'Dones empáticos y psiónicos de alto nivel que le permiten percibir, canalizar y alterar el estado emocional de cualquier ser vivo mediante contacto o proximidad. Es una maestra consumada de las artes marciales del templo, dirigiendo golpes a puntos de presión de forma letal.',
        'High-level empathic and psionic gifts allowing her to perceive, channel, and alter the emotional state of any living being through contact or proximity. She is a consummate master of the temple\'s martial arts, directing strikes lethally at pressure points.',
        'EVALUACIÓN DE CAMPO: Activo de control y pacificación. Su ataque de artes marciales (Alcance 0, 3 dados, precisión 4+) neutraliza con agilidad. En juego destaca por su Meditar (robar rasgos o cargar energía) y su Control Empático. Su Habilidad de Aparición en el tablero debilita el control del hambre de los oponentes: los Héroes Zombi a Alcance 1 se consideran Voraces en nivel de hambre 3. Resistencia: 3.',
        'FIELD DOSSIER: Control and pacification asset. Her martial arts attack (Range 0, 3 dice, 4+ hit) neutralizes with agility. In gameplay, she excels with her Meditate (draw traits or gather power) and her Empathic Control. Her board Spawn Ability weakens opponents\' hunger control: Zombie Heroes within Range 1 are considered Ravenous at hunger level 3. Toughness: 3.'
    ),
    nebula: entry(
        'Nebula es una pirata espacial y cyborg de la galaxia de Andrómeda que fue adoptada y torturada sistemáticamente por Thanos para ser la rival de Gamora. Reemplazando progresivamente partes de su cuerpo con implantes mecánicos tras cada derrota, Nebula desarrolló un frío instinto de guerra y supervivencia en el cosmos.',
        'Nebula is a space pirate and cyborg from the Andromeda galaxy who was adopted and systematically tortured by Thanos to be Gamora\'s rival. Progressively replacing parts of her body with mechanical implants after each defeat, Nebula forged a cold instinct for war and survival in the cosmos.',
        'Fisiología extensamente mejorada con implantes cibernéticos avanzados. Posee fuerza y reflejos aumentados, un sistema inmunológico sintético autorreparador de alta velocidad y un ojo cibernético de puntería avanzada integrado con su rifle de precisión.',
        'Physiology extensively upgraded with advanced cybernetic implants. She possesses enhanced strength and reflexes, a high-speed self-repairing synthetic immune system, and a cybernetic eye for advanced aiming integrated with her sniper rifle.',
        'EVALUACIÓN DE CAMPO: Activo autónomo de presión de largo alcance. Dispara su rifle de precisión (Alcance 0-2, 1 dado, precisión 2+) con gran precisión. Brilla con su habilidad Francotirador (ignorar prioridad) y Mejoras Biónicas. Su Habilidad de Aparición le permite atacar desde 1 Zona de distancia y, cuando es eliminada, inflige de inmediato 1 Herida directa a 1 Héroe Zombi en su Zona. Resistencia: 3.',
        'FIELD DOSSIER: Autonomous long-range pressure asset. Fires her targeting rifle (Range 0-2, 1 die, 2+ hit) with great accuracy. Shines with her Sniper skill (ignore priority) and Bionic Enhancements. Her Spawn Ability allows her to attack from 1 Zone away, and when eliminated, she instantly inflicts 1 direct Wound on 1 Zombie Hero in her Zone. Toughness: 3.'
    ),
    nova: entry(
        'Richard Rider era un estudiante de secundaria promedio de Long Island hasta que fue seleccionado al azar por el moribundo centurión Rhomann Dey para heredar sus poderes y la herencia del Cuerpo Nova de Xandar. Tras verse empujado a guerras cósmicas de escala destructiva, Rider maduró hasta convertirse en Nova Prime, el líder defensivo del cosmos.',
        'Richard Rider was an average Long Island high school student until he was randomly selected by the dying centurion Rhomann Dey to inherit his powers and the legacy of the Xandarian Nova Corps. Thrust into cosmic wars of destructive scale, Rider matured into Nova Prime, the defensive leader of the cosmos.',
        'Conexión directa con la Fuerza Nova a través del casco de Centurión. Le otorga vuelo táctico hiperveloz, fuerza sobrehumana, resistencia extraordinaria a la presión espacial e impactos, y la capacidad de absorber y canalizar ráfagas de energía gravimétrica destructivas.',
        'Direct connection with the Nova Force through the Centurion helmet. It grants hyper-velocity tactical flight, superhuman strength, extraordinary resistance to spatial pressure and impacts, and the ability to absorb and channel destructive gravimetric energy blasts.',
        'EVALUACIÓN DE CAMPO: Activo de respuesta e interceptación veloz. Dispara ráfagas nova a distancia (Alcance 0-1, 2 dados, precisión 3+). En juego brilla por su Campo de Fuerza y su habilidad Hiperpuerta. Su Habilidad de Aparición es sumamente peligrosa: aparece rodeado de Soldados (S.H.I.E.L.D. Troopers) cuyo número escala con el Nivel de Peligro del juego (Azul: 2, Amarillo: 3, Naranja: 4, Rojo: 5). Resistencia: 4.',
        'FIELD DOSSIER: High-speed response and interception asset. Fires nova shots at range (Range 0-1, 2 dice, 3+ hit). In gameplay, he shines with his Forcefield and Hypergate skills. His Spawn Ability is highly dangerous: he spawns flanked by S.H.I.E.L.D. Troopers whose number scales with the game\'s Danger Level (Blue: 2, Yellow: 3, Orange: 4, Red: 5). Toughness: 4.'
    ),
    rocket: entry(
        'Rocket Raccoon es el resultado de crueles experimentos genéticos y cibernéticos de alta densidad realizados en el planeta Halfworld en el cuadrante Keystone. Combinando una vida de supervivencia y cazarrecompensas con una mente mecánica de nivel genio, Rocket se convirtió en el cerebro táctico de artillería de los Guardianes de la Galaxia.',
        'Rocket Raccoon is the result of cruel high-density genetic and cybernetic experiments performed on the planet Halfworld in the Keystone quadrant. Combining a life of raw survival and bounty hunting with a genius-level mechanical mind, Rocket became the tactical heavy-ordnance brain of the Guardians of the Galaxy.',
        'Fisiología animal mejorada quirúrgicamente con microimplantes de combate. Posee reflejos y sentidos animales hiperdesarrollados, maestría absoluta en ingeniería de armamento e improvisación de explosivos, y un manejo soberbio de artillería pesada e irregular.',
        'Animal physiology surgically enhanced with combat micro-implants. He possesses hyper-developed animal reflexes and senses, absolute mastery of weapons engineering and explosive improvisation, and superb handling of heavy and irregular ordnance.',
        'EVALUACIÓN DE CAMPO: Activo de fuego irregular y soporte pesado. Ataca a distancia con su arsenal (Alcance 0-1, 2 dados, precisión 3+). En juego destaca por su Disparo Sobrecargado y Barrera Láser. Su Habilidad de Aparición lo hace aparecer respaldado por 2 Especialistas de S.H.I.E.L.D. Además, tanto él como todos sus especialistas a Alcance 1 pueden atacar desde 1 Zona de distancia. Resistencia: 3.',
        'FIELD DOSSIER: Irregular-fire and heavy-support asset. Attacks at range with his arsenal (Range 0-1, 2 dice, 3+ hit). In gameplay, he stands out with his Overload Shot and Laser Barrage. His Spawn Ability causes him to spawn backed by 2 S.H.I.E.L.D. Specialists. Furthermore, both he and all his specialists within Range 1 can attack from 1 Zone away. Toughness: 3.'
    ),
    silversurfer: entry(
        'Norrin Radd fue un astrónomo del planeta Zenn-La que sacrificó su libertad y su alma entregándose al Devorador de Mundos, Galactus, para salvar su mundo natal de la extinción. Transformado por el Poder Cósmico en el Heraldo Plateado, Norrin vagó por el cosmos buscando planetas deshabitados antes de rebelarse y proteger la Tierra.',
        'Norrin Radd was an astronomer from the planet Zenn-La who sacrificed his freedom and soul to the Devourer of Worlds, Galactus, to save his home world from extinction. Transformed by the Power Cosmic into the Silver Surfer, Norrin roamed the cosmos searching for uninhabited planets before rebelling to protect Earth.',
        'Imbuido con el Poder Cósmico, lo que le otorga vuelo interestelar a hipervelocidad sobre su tabla cósmica mística, fuerza y resistencia física colosales, manipulación de energía a nivel subatómico, autocuración molecular inmediata e inmunidad a daños cósmicos.',
        'Imbued with the Power Cosmic, granting him hyper-velocity interstellar flight on his mystic cosmic board, colossal physical strength and durability, subatomic energy manipulation, immediate molecular self-healing, and immunity to cosmic damage.',
        'EVALUACIÓN DE CAMPO: Activo de escala estratégica planetaria. Ataca a distancia con rayos cósmicos (Alcance 0-1, 2 dados, precisión 3+). Destaca en juego con su Tabla Cósmica y su habilidad Velocidad de la Luz (moverse 3 zonas ignorando enemigos por 1 acción). Su Habilidad de Aparición le otorga una alta evasión aérea: los ataques dirigidos a su Zona a Alcance 1 o más sufren un penalizador de -1 a las tiradas. Resistencia: 4.',
        'FIELD DOSSIER: Planetary strategic-scale asset. Attacks at range with cosmic rays (Range 0-1, 2 dice, 3+ hit). In gameplay, he excels with his Cosmic Board and Lightspeed skills (move 3 zones ignoring enemies for 1 action). His Spawn Ability grants him high aerial evasion: attacks directed at his Zone from Range 1 or more suffer a -1 penalty on rolls. Toughness: 4.'
    ),
    professorx: entry(
        'Charles Francis Xavier es uno de los telépatas más poderosos del mundo y el visionario fundador de los X-Men. Dedicó su vida y su inmensa fortuna a promover la coexistencia pacífica entre mutantes y humanos, construyendo el Instituto Xavier para entrenar a jóvenes mutantes a controlar sus dones bajo un marco de responsabilidad ética.',
        'Charles Francis Xavier is one of the world\'s most powerful telepaths and the visionary founder of the X-Men. He dedicated his life and immense fortune to promoting peaceful coexistence between mutants and humans, building the Xavier Institute to train young mutants to master their gifts under an ethical framework of responsibility.',
        'Mutante de nivel Alfa con telepatía táctica masiva. Puede leer, proyectar, borrar y reescribir pensamientos con un alcance kilométrico, proyectar ilusiones psíquicas completas, comunicarse mentalmente a escala global con Cerebro y neutralizar psiquis enemigas.',
        'Alpha-level mutant with massive tactical telepathy. He can read, project, erase, and rewrite thoughts across a kilometric range, project complete psychic illusions, communicate mentally on a global scale with Cerebro, and neutralize enemy minds.',
        'EVALUACIÓN DE CAMPO: Activo de inteligencia y coordinación mental. Ataca a distancia con ráfagas mentales (Alcance 0-1, 1 dado, precisión 2+). Brilla con su habilidad Guía Telepática y Camuflaje Telepático. Su Habilidad de Aparición ataca mentalmente a los oponentes de forma constante: cada Héroe Zombi en el mapa debe lanzar un dado al final de su turno; con un 5+, sufren 1 Herida directa. Resistencia: 3.',
        'FIELD DOSSIER: Intelligence and mental coordination asset. Attacks at range with mind bolts (Range 0-1, 1 die, 2+ hit). Shines with his Telepathic Guidance and Telepathic Camouflage skills. His Spawn Ability mentally attacks opponents constantly: every Zombie Hero on the map must roll a die at the end of their turn; on a 5+, they suffer 1 direct Wound. Toughness: 3.'
    ),
    captainamerica: entry(
        'Steve Rogers era un joven frágil de Brooklyn rechazado por el ejército durante la Segunda Guerra Mundial debido a su condición física. Sometido al exitoso "Proyecto Renacimiento", fue inyectado con el Suero del Súper Soldado, convirtiéndose en el Capitán América, símbolo de libertad y líder indiscutible de los Vengadores.',
        'Steve Rogers was a frail Brooklyn youth rejected by the military during World War II due to his physical condition. Subjected to the successful "Project Rebirth," he was injected with the Super-Soldier Serum, becoming Captain America, symbol of liberty and undisputed leader of the Avengers.',
        'Fisiología mejorada en el cenit de la evolución humana: fuerza, resistencia, agilidad y reflejos superhumanos, complementados con una mente táctica excepcional y una voluntad inquebrantable. Maneja su escudo de vibranium, capaz de absorber impactos cinéticos sin inercia.',
        'Enhanced physiology at the zenith of human evolution: superhuman strength, endurance, agility, and reflexes, complemented by an exceptional tactical mind and unwavering will. He wields his vibranium shield, capable of absorbing kinetic impacts without inertia.',
        'EVALUACIÓN DE CAMPO: Mando táctico de primera línea y protector de escuadra. Ataca con su escudo (Alcance 0-1, 2 dados, precisión 3+). En juego destaca por su habilidad ¡Puedo Hacer Esto Todo el Día! y Rebote. Su Habilidad de Aparición inspira y potencia a las fuerzas aliadas: todos los Soldados (Troopers) y Guardias que se activen a Alcance 1 de él realizan +1 Acción en su turno. Resistencia: 4.',
        'FIELD DOSSIER: Front-line tactical command and squad shield. Attacks with his shield (Range 0-1, 2 dice, 3+ hit). In gameplay, he stands out with his I Can Do This All Day! and Ricochet skills. His Spawn Ability inspires and buffs allied forces: all Troopers and Guards activating within Range 1 of him perform +1 Action on their turn. Toughness: 4.'
    ),
    gambit: entry(
        'Remy LeBeau creció en los callejones del Gremio de Ladrones de Nueva Orleans antes de manifestar su poder mutante y convertirse en el carismático Gambit. Con un historial marcado por tratos de contrabando y lealtades elásticas, encontró redención e identidad junto a los X-Men, convirtiéndose en uno de sus defensores más tenaces.',
        'Remy LeBeau grew up in the alleyways of the New Orleans Thieves Guild before manifesting his mutant power and becoming the charismatic Gambit. With a record marked by smuggling deals and elastic loyalties, he found redemption and identity with the X-Men, becoming one of their most tenacious defenders.',
        'Capacidad mutante de cargar objetos con energía cinética altamente inestable mediante contacto directo. Al lanzar proyectiles (como barajas de cartas personalizadas) cargados cinéticamente, estos detonan con fuerza explosiva masiva tras el impacto.',
        'Mutant ability to charge objects with highly unstable kinetic energy through direct contact. By throwing kinetically charged projectiles (such as his custom decks of cards), they detonate with massive explosive force upon impact.',
        'EVALUACIÓN DE CAMPO: Activo de hostigamiento a media distancia. Ataca cuerpo a cuerpo con su bastón Bo (Alcance 0, 2 dados, precisión 3+). Destaca en juego por su Lanzamiento de Cartas y Lanzamiento Cargado para eliminar grupos de enemigos. Su Habilidad de Aparición le permite atacar desde un Alcance igual al Nivel de Peligro más alto entre los Héroes Zombi (de 1 a 4 Zonas de distancia), golpeando a todos en la Zona. Resistencia: 3.',
        'FIELD DOSSIER: Mid-range harassment asset. Attacks in close quarters with his Bo staff (Range 0, 2 dice, 3+ hit). Stands out in gameplay with his Card Throw and Charged Toss skills to eliminate enemy groups. His Spawn Ability allows him to attack from a Range equal to the highest Danger Level among the Zombie Heroes (from 1 to 4 Zones away), hitting everyone in the Zone. Toughness: 3.'
    ),
    hawkeye: entry(
        'Clint Barton creció en circos ambulantes donde dominó el tiro con arco antes de unirse al crimen y luego ser reformado por Iron Man y S.H.I.E.L.D. Miembro veterano de los Vengadores, Hawkeye se ha ganado su lugar entre dioses y monstruos armada únicamente con una puntería perfecta, una voluntad de acero y un arco táctico de alta precisión.',
        'Clint Barton grew up in traveling carnivals where he mastered archery before turning to crime and later being reformed by Iron Man and S.H.I.E.L.D. A veteran member of the Avengers, Hawkeye has earned his place among gods and monsters armed solely with flawless marksmanship, a steel will, and a high-precision tactical bow.',
        'Puntería física absoluta con cualquier proyectil, visión e intuición balística espacial hiperdesarrolladas, y maestría en artes marciales y esgrima (Ronin). Emplea un carcaj de flechas con puntas personalizadas: explosivas, de choque eléctrico, gas lacrimógeno, ácido y ganchos de agarre.',
        'Absolute physical marksmanship with any projectile, hyper-developed spatial ballistic vision and intuition, and mastery in martial arts and swordsmanship (Ronin). He employs a quiver of trick arrows: explosive, electrical shock, tear gas, acid, and grappling hooks.',
        'EVALUACIÓN DE CAMPO: Tirador táctico de precisión y control. Dispara sus flechas a larga distancia (Alcance 0-2, 1 dado, precisión 2+) con Precisión Explosiva. Destaca por su habilidad Tirador Experto. Su Habilidad de Aparición le permite atacar desde 3 Zonas de distancia; tras disparar, lanza un dado y con un 5+ realiza de inmediato un ataque gratuito (el cual puede encadenar más ataques). Resistencia: 3.',
        'FIELD DOSSIER: Tactical precision and control marksman. Fires his arrows at long range (Range 0-2, 1 die, 2+ hit) with Explosive Precision. Stands out with his Expert Marksman skill. His Spawn Ability allows him to attack from 3 Zones away; after firing, roll a die, and on a 5+ he executes an immediate free attack (which can chain further attacks). Toughness: 3.'
    ),
    hulk: entry(
        'El brillante físico Bruce Banner fue expuesto accidentalmente a una dosis masiva de radiación gamma durante la prueba de una bomba militar. A partir de ese trauma, Banner quedó condenado a transformarse bajo estrés o rabia en Hulk, el coloso verde cuya fuerza e ira destructiva no tienen límites en el universo.',
        'Brilliant physicist Bruce Banner was accidentally exposed to a massive dose of gamma radiation during a military bomb test. Following that trauma, Banner was condemned to transform under stress or rage into the Hulk, the green colossus whose strength and destructive anger have no limits in the universe.',
        'Fisiología mutada por radiación gamma masiva. Posee fuerza física colosal de escala infinita (aumenta proporcionalmente con su rabia), factor de curación regenerativo instantáneo capaz de curar desmembramientos en segundos e inmunidad total a enfermedades, toxinas y temperaturas extremas.',
        'Physiology mutated by massive gamma radiation. He possesses infinite-scale colossal physical strength (increasing proportionally with his rage), an instantaneous regenerative healing factor capable of healing dismemberment in seconds, and total immunity to diseases, toxins, and extreme temperatures.',
        'EVALUACIÓN DE CAMPO: Fuerza de la naturaleza de destrucción masiva. Aplasta cuerpo a cuerpo con una fuerza devastadora (Alcance 0, 3 dados, precisión 4+). En juego brilla por su habilidad Trueno e Ira Ilimitada (acción de ataque extra). Su Habilidad de Aparición en el tablero le otorga una invulnerabilidad física absoluta: solo puede ser eliminado mediante ataques directos de Devorar. Resistencia: 5.',
        'FIELD DOSSIER: Mass destruction force of nature. Crushes in close quarters with devastating force (Range 0, 3 dice, 4+ hit). In gameplay, he shines with his Thunderclap and Unlimited Rage skills (extra attack action). His board Spawn Ability grants him absolute physical invulnerability: he can only be eliminated by direct Devour attacks. Toughness: 5.'
    ),
    ironman: entry(
        'Tony Stark pasó de industrial armamentístico arrogante a arquitecto de su propia redención tras ser capturado y herido de gravedad por metralla en el pecho. Construyó su primera armadura en cautiverio para salvar su vida y escapar, convirtiéndose en Iron Man, el motor de desarrollo y liderazgo de los Vengadores.',
        'Tony Stark went from arrogant arms industrialist to architect of his own redemption after being captured and gravely wounded by shrapnel in his chest. He built his first armor in captivity to save his life and escape, becoming Iron Man, the engine of development and leadership of the Avengers.',
        'Intelecto de nivel genio polifacético, experto en ingeniería robótica, física de alta energía e inteligencia artificial. Viste armaduras de alta tecnología modulares que integran vuelo supersónico, cañones repulsores, un núcleo Arc, misiles tácticos y escudos energéticos.',
        'Polymath genius-level intellect, expert in robotics engineering, high-energy physics, and artificial intelligence. He wears high-tech modular armors integrating supersonic flight, repulsor cannons, an Arc reactor, tactical missiles, and energy shields.',
        'EVALUACIÓN DE CAMPO: Activo de supremacía tecnológica y fuego flexible. Ataca con su repulsor a distancia (Alcance 0-1, 2 dados, precisión 3+). En juego brilla con su habilidad Maniobras Evasivas (moverse gratis tras eliminar enemigos) e I.A. Friday. Su Habilidad de Aparición le permite atacar a 2 Zonas de distancia; si es atacado pero no eliminado, huye 1 Zona e inflige de inmediato 1 Herida al atacante. Resistencia: 4.',
        'FIELD DOSSIER: Technological supremacy and flexible fire asset. Attacks with his repulsor at range (Range 0-1, 2 dice, 3+ hit). In gameplay, he shines with his Evasive Maneuvers skill (move free after eliminating enemies) and Friday A.I. His Spawn Ability allows him to attack from 2 Zones away; if attacked but not eliminated, he retreats 1 Zone and instantly inflicts 1 Wound on the attacker. Toughness: 4.'
    ),
    namor: entry(
        'Namor, el hijo mestizo de una princesa de Atlantis y un capitán de barco humano, es el orgulloso soberano de los océanos. Con un temperamento tan impredecible como el mar, ha actuado tanto de defensor de la Tierra junto a los Defensores e Invasores como de adversario implacable de la superficie para defender Atlantis.',
        'Namor, the hybrid son of an Atlantean princess and a human sea captain, is the proud sovereign of the oceans. With a temperament as unpredictable as the sea, he has acted both as a defender of Earth alongside the Defenders and Invaders, and as a relentless adversary of the surface to defend Atlantis.',
        'Fisiología híbrida atlántica de nivel rey. Posee fuerza física colosal de clase 100 en el agua y fuera de ella, velocidad y resistencia superhumanos, respiración anfibia y alas vestigiales en los tobillos que le permiten volar a gran velocidad y agilidad táctica.',
        'Hybrid Atlantean king-level physiology. He possesses class-100 colossal physical strength both in and out of the water, superhuman speed and durability, amphibious respiration, and vestigial ankle-wings allowing high-speed flight and tactical agility.',
        'EVALUACIÓN DE CAMPO: Activo de asalto anfibio y choque real. Ataca cuerpo a cuerpo con su aplastamiento profundo (Alcance 0, 2 dados, precisión 3+). En juego destaca por sus Alas Vestigiales (moverse +1 zona ignorando enemigos) y Venganza Profunda. Su Habilidad de Aparición le otorga una alta frecuencia ofensiva: realiza una cantidad de acciones por activación igual a 1 más el número de Héroes Zombi heridos en juego (máximo 4 acciones). Resistencia: 5.',
        'FIELD DOSSIER: Amphibious assault and royal shock asset. Attacks in close quarters with his deep crush (Range 0, 2 dice, 3+ hit). In gameplay, he excels with his Vestigial Wings (move +1 zone ignoring enemies) and Deep Vengeance. His Spawn Ability grants him high offensive frequency: he performs a number of actions per activation equal to 1 plus the number of wounded Zombie Heroes in play (maximum 4 actions). Toughness: 5.'
    ),
    sabretooth: entry(
        'Victor Creed es un asesino y mercenario mutante salvaje que ha operado en las sombras del espionaje militar durante más de un siglo. Impulsado por un instinto sádico y una rivalidad psicopática y eterna con Wolverine, Sabretooth ha servido a programas secretos como Weapon X y a la Hermandad de Mutantes.',
        'Victor Creed is a savage mutant assassin and mercenary who has operated in the shadows of military espionage for over a century. Driven by a sadistic instinct and a psychopathic, eternal rivalry with Wolverine, Sabretooth has served secret programs like Weapon X and the Brotherhood of Mutants.',
        'Factor de curación regenerativo acelerado idéntico al de Wolverine, sentidos animales hiperdesarrollados para rastreo olfativo y auditivo, agilidad física sobrehumana y garras retráctiles de alta densidad reforzadas capaces de desgarrar tejido celular y metales tácticos.',
        'Accelerated regenerative healing factor identical to Wolverine\'s, hyper-developed animal senses for olfactory and auditory tracking, superhuman physical agility, and reinforced high-density retractable claws capable of tearing through cellular tissue and tactical metals.',
        'EVALUACIÓN DE CAMPO: Depredador de asalto de corta distancia. Ataca cuerpo a cuerpo con sus garras feroces (Alcance 0, 3 dados, precisión 4+) con gran facilidad de combo. Destaca con Carga con Salto y Depredador Alfa. Su Habilidad de Aparición en el tablero castiga los errores de ataque cercanos: todo Héroe Zombi que falle un ataque en su misma Zona (obteniendo un resultado de 1) sufre de inmediato 1 Herida. Resistencia: 4.',
        'FIELD DOSSIER: Close-quarters assault predator. Attacks in close combat with his feral claws (Range 0, 3 dice, 4+ hit) with great combo potential. Stands out with Leaping Charge and Alpha Predator. His board Spawn Ability punishes close range attack errors: any Zombie Hero missing an attack in his Zone (rolling a 1 result) instantly suffers 1 Wound. Toughness: 4.'
    ),
    shangchi: entry(
        'Shang-Chi fue criado desde su infancia en un monasterio aislado de China por su padre Fu Manchú, quien lo sometió a un adiestramiento brutal para convertirlo en el asesino definitivo. Al descubrir las malvadas intenciones de su padre, Shang-Chi huyó y dedicó su vida a combatir su imperio criminal, aliándose con héroes occidentales.',
        'Shang-Chi was raised from childhood in an isolated monastery in China by his father Fu Manchu, who subjected him to brutal training to forge him into the ultimate assassin. Upon discovering his father\'s evil intent, Shang-Chi fled and dedicated his life to fighting his criminal empire, allying with Western heroes.',
        'Maestría absoluta en todas las disciplinas marciales chinas (Wushu) y control perfecto del Chi, lo que le permite desviar proyectiles ligeros con sus manos, concentrar su energía para asestar golpes de gran impacto físico y optimizar la resistencia y recuperación de su cuerpo de forma consciente.',
        'Absolute mastery of all Chinese martial arts (Wushu) and perfect control of Chi, allowing him to deflect light projectiles with his bare hands, concentrate energy to strike with massive physical impact, and consciously optimize his body\'s endurance and recovery.',
        'EVALUACIÓN DE CAMPO: Activo de excelencia marcial y contragolpe. Ataca cuerpo a cuerpo con técnicas de artes marciales (Alcance 0, 3 dados, precisión 4+) con Voluntad de Hierro para sanarse. Brilla por su Manipulación del Chi y Empoderamiento de los Diez Anillos. Su Habilidad de Aparición castiga a sus agresores: si su Zona es atacada pero no es eliminado, el atacante sufre de inmediato 1 Herida y su turno termina automáticamente. Resistencia: 4.',
        'FIELD DOSSIER: Martial excellence and counterstrike asset. Attacks in close quarters with martial arts techniques (Range 0, 3 dice, 4+ hit) with Iron Resolve to self-heal. Shines through Chi Manipulation and Ten Rings Empowerment. His Spawn Ability punishes his attackers: if his Zone is attacked but he is not eliminated, the attacker instantly suffers 1 Wound and their turn automatically ends. Toughness: 4.'
    ),
    spiderwoman: entry(
        'Jessica Drew adquirió sus asombrosos dones debido a experimentos con suero de araña e irradiación de genes realizados por su padre científico en el monte Wundagore. Manipulada en su juventud por HYDRA para ser una asesina, Jessica logró liberarse y sirvió como agente doble para S.H.I.E.L.D., S.W.O.R.D. y los Vengadores.',
        'Jessica Drew acquired her amazing gifts from spider serum experiments and gene radiation performed by her scientist father on Mount Wundagore. Manipulated in her youth by HYDRA to be an assassin, Jessica broke free and served as a double agent for S.H.I.E.L.D., S.W.O.R.D., and the Avengers.',
        'Fuerza y reflejos superhumanos, bioelectricidad canalizable en "descargas de veneno" concentradas, capacidad de planear mediante membranas aerodinámicas en su traje, adherencia táctil y secreción psiónica de feromonas capaz de inducir calma, atracción o terror en seres vivos.',
        'Superhuman strength and reflexes, bioelectricity channelable into concentrated "venom blasts," gliding capability via aerodynamic suit membranes, wall-crawling, and psionic pheromone secretion capable of inducing calm, attraction, or terror in living beings.',
        'EVALUACIÓN DE CAMPO: Activo de espionaje encubierto y control táctico. Ataca cuerpo a cuerpo con artes marciales (Alcance 0, 3 dados, precisión 4+). Destaca en juego por su Disparo Veneno (empujar enemigos) y Feromonas. Su Habilidad de Aparición le permite atacar desde 1 Zona de distancia, y obliga a los Héroes Zombi atacados por ella a descartar todas sus cartas de Rasgo o sufrir 1 Herida adicional. Resistencia: 3.',
        'FIELD DOSSIER: Covert espionage and tactical control asset. Attacks in close quarters with martial arts (Range 0, 3 dice, 4+ hit). Excels in gameplay with her Venom Blast (push enemies) and Pheromones. Her Spawn Ability allows her to attack from 1 Zone away, and forces targeted Zombie Heroes to discard all their Trait cards or suffer 1 extra Wound. Toughness: 3.'
    ),
    starlord: entry(
        'Peter Quill creció en la Tierra ignorando que su padre era el emperador alienígena J\'son de Spartax. Tras la muerte de su madre a manos de alienígenas Badoon, Quill se unió a la NASA antes de adentrarse en el espacio profundo y adoptar la identidad de Star-Lord, el líder carismático y descarado de los Guardianes de la Galaxia.',
        'Peter Quill grew up on Earth unaware that his father was the alien emperor J\'son of Spartax. Following his mother\'s death at the hands of Badoon aliens, Quill joined NASA before venturing into deep space and adopting the identity of Star-Lord, the charismatic and cheeky leader of the Guardians of the Galaxy.',
        'Fisiología híbrida espartana que le otorga fuerza y resistencia mejoradas, y una longevidad extendida. Experto tirador táctico, utiliza botas cohete para vuelo de corta distancia y empuña sus pistolas láser duales elementales capaces de canalizar energía elemental.',
        'Hybrid Spartoi physiology granting him enhanced strength, durability, and extended longevity. An expert tactical marksman, he uses rocket boots for short-range flight and wields his dual elemental laser pistols capable of channeling elemental energy.',
        'EVALUACIÓN DE CAMPO: Liderazgo flexible y apoyo táctico móvil. Ataca a distancia con sus pistolas láser (Alcance 0-1, 2 dados, precisión 3+). En juego brilla por sus Propulsores para moverse 3 zonas y ¡Reunión! para robar rasgos heroicos para el equipo. Su Habilidad de Aparición entorpece las capacidades enemigas: todo Héroe Zombi que se active dentro de su Línea de Visión pierde de inmediato 1 Acción de su turno. Resistencia: 3.',
        'FIELD DOSSIER: Flexible leadership and mobile tactical support. Attacks at range with his laser pistols (Range 0-1, 2 dice, 3+ hit). In gameplay, he shines with his Boosters to move 3 zones and Huddle Up! to draw heroic traits for the team. His Spawn Ability hinders enemy capabilities: any Zombie Hero activating within his Line of Sight instantly loses 1 Action from their turn. Toughness: 3.'
    ),
    vulture: entry(
        'Adrian Toomes fue un talentoso ingeniero electrónico e inventor independiente cuya vida dio un giro criminal tras ser estafado y robado por su socio comercial. Lleno de resentimiento, Toomes construyó su arnés electromagnético avanzado y adoptó el manto de Vulture, convirtiéndose en uno de los enemigos aéreos más veteranos de Spider-Man.',
        'Adrian Toomes was a talented electronics engineer and independent inventor whose life took a criminal turn after being swindled and robbed by his business partner. Filled with resentment, Toomes built his advanced electromagnetic harness and adopted the mantle of Vulture, becoming one of Spider-Man\'s oldest aerial enemies.',
        'Acceso al arnés tecnológico electromagnético avanzado de Vulture. Le permite vuelo silencioso de alta maniobrabilidad táctica, aumenta su fuerza física a niveles sobrehumanos, ralentiza biológicamente su envejecimiento corporal e integra alas afiladas capaces de cortar estructuras sólidas.',
        'Access to Vulture\'s advanced electromagnetic technology harness. It grants silent flight of high tactical maneuverability, enhances his physical strength to superhuman levels, biologically slows his physical aging, and integrates razor-sharp wings capable of slicing solid structures.',
        'EVALUACIÓN DE CAMPO: Hostigador de asalto vertical rápido. Taja cuerpo a cuerpo con sus alas de metal (Alcance 0, 2 dados, precisión 3+). En juego destaca por su Zarpazo Volador (eliminar caminantes gratis al moverse) y Alzar el Vuelo. Su Habilidad de Aparición en el tablero remueve 2 Soldados (S.H.I.E.L.D. Troopers) a Alcance 1 de él cuando se activa; por cada uno removido, realiza +1 Acción táctica. Resistencia: 3.',
        'FIELD DOSSIER: Fast vertical-assault harasser. Slices in close quarters with his metal wings (Range 0, 2 dice, 3+ hit). In gameplay, he stands out with his Flying Slash (free walker elimination upon moving) and Take Flight. His board Spawn Ability removes 2 Troopers within Range 1 of him when he activates; for each one removed, he performs +1 tactical Action. Toughness: 3.'
    ),
    warmachine: entry(
        'El teniente coronel James "Rhodey" Rhodes fue un piloto de combate condecorado del Cuerpo de Marines que entabló una profunda amistad con Tony Stark tras rescatarlo. Como uno de los aliados más estables y leales de Stark, Rhodes asumió el control de la armadura fuertemente artillada War Machine, actuando como enlace militar de primera línea.',
        'Lieutenant Colonel James "Rhodey" Rhodes was a decorated Marine Corps combat pilot who forged a deep friendship with Tony Stark after rescuing him. As one of Stark\'s most stable and loyal allies, Rhodes assumed control of the heavily weaponized War Machine armor, serving as a front-line military liaison.',
        'Viste la armadura War Machine, modificada a partir de los diseños de Stark. A diferencia de las armaduras estilizadas de Iron Man, prioriza blindaje militar balístico pesado de alta densidad, sistemas de artillería pesada (ametralladora Gatling montada, lanzamisiles, cañón láser de hombro y repulsores modificados).',
        'Wears the War Machine armor, modified from Stark\'s designs. Unlike Iron Man\'s streamlined suits, it prioritizes high-density ballistic military plating and heavy weapon platforms (mounted Gatling gun, tactical missile launchers, shoulder laser cannon, and modified repulsors).',
        'EVALUACIÓN DE CAMPO: Unidad de artillería táctica y fuego de supresión pesado. Dispara a distancia con su armería (Alcance 0-1, 2 dados, precisión 3+) con gran capacidad de fuego encadenado (Gatling Gun). Brilla con su Lanzamisil para dañar grupos grandes. Su Habilidad de Aparición bombardea el tablero de forma masiva: si hay Héroes Zombi en su línea de visión cuando se activa, lanza un dado y con un 5+ todos sufren 1 Herida. Resistencia: 4.',
        'FIELD DOSSIER: Tactical artillery and heavy suppression unit. Fires at range with his armory (Range 0-1, 2 dice, 3+ hit) with great chain-fire capability (Gatling Gun). Shines with his Rocket Launcher to damage large groups. His Spawn Ability bombards the board massively: if there are Zombie Heroes in sight when he activates, roll a die, and on a 5+ they all suffer 1 Wound. Toughness: 4.'
    ),
    wasp: entry(
        'Janet Van Dyne, una diseñadora de moda e ingeniera social brillante, se unió al científico Hank Pym para vengar la muerte de su padre científico, convirtiéndose en la heroína Wasp. Cofundadora y líder histórica de los Vengadores, Janet es una figura clave en la cohesión y moral del equipo, uniendo carisma y táctica quirúrgica.',
        'Janet Van Dyne, a brilliant fashion designer and social engineer, joined scientist Hank Pym to avenge her father\'s death, becoming the hero Wasp. Co-founder and historical leader of the Avengers, Janet is a key figure in team cohesion and morale, uniting charisma with surgical tactics.',
        'Acceso al traje tecnológico de Wasp alimentado por Partículas Pym. Le permite reducir su tamaño corporal a escala microscópica mientras vuela mediante alas bio-sintéticas translúcidas, y disparar descargas bioeléctricas altamente dolorosas concentradas como la "Picadura de Avispa".',
        'Access to the technology Wasp suit powered by Pym Particles. It allows her to shrink her body to microscopic scale while flying via translucent bio-synthetic wings, and fire highly painful concentrated bio-electrical discharges known as the "Wasp\'s Sting."',
        'EVALUACIÓN DE CAMPO: Activo de hostigamiento quirúrgico e inserción mínima. Dispara a distancia con su Picadura de Avispa (Alcance 0-1, 2 dados, precisión 3+) ignorando la prioridad de objetivos. Destaca con Aprovechar Huecos y Alas Biosintéticas. Su Habilidad de Aparición dificulta el fuego en su contra: los ataques a distancia dirigidos a su Zona solo impactan con precisión de 5+. Resistencia: 3.',
        'FIELD DOSSIER: Surgical harassment and minimal insertion asset. Fires at range with her Wasp\'s Sting (Range 0-1, 2 dice, 3+ hit) ignoring target priority. Stands out with Exploit Openings and Bio-Synthetic Wings. Her Spawn Ability makes targeting her difficult: ranged attacks directed at her Zone only hit on a 5+ roll. Toughness: 3.'
    ),
    wintersoldier: entry(
        'James Buchanan "Bucky" Barnes fue el leal compañero del Capitán América en las trincheras de la Segunda Guerra Mundial. Tras caer de un tren y ser dado por muerto, fue rescatado y reprogramado por el departamento soviético de Hydra como el Winter Soldier, un asesino silencioso de operaciones negras que pasó décadas en estasis.',
        'James Buchanan "Bucky" Barnes was Captain America\'s loyal companion in the trenches of World War II. After falling from a train and being presumed dead, he was rescued and brainwashed by a Soviet Hydra department as the Winter Soldier, a silent black-ops assassin spent decades in stasis.',
        'Fisiología entrenada en el límite humano, mejorada cibernéticamente con un brazo metálico biónico de gran resistencia que multiplica su fuerza física. Experto en combate cercano de infiltración, sabotaje, puntería de élite con rifles tácticos y espionaje negro de alta letalidad.',
        'Physiology trained at the human peak, cybernetically enhanced with an incredibly durable bionic metal arm multiplying his physical strength. Expert in close-quarters infiltration, sabotage, elite marksmanship with tactical rifles, and high-lethality black-ops espionage.',
        'EVALUACIÓN DE CAMPO: Activo de operaciones encubiertas de alta letalidad. Combate cuerpo a cuerpo con su hoja de combate (Alcance 0, 2 dados, precisión 3+) asesinando caminantes gratis. En juego destaca por Resistencia Ilimitada y Experto en Combate Cuerpo a Cuerpo. Su Habilidad de Aparición castiga la proximidad enemiga: cada vez que se roba una carta de ¡Invasión!, todo Héroe Zombi a Alcance 1 de él sufre de inmediato 1 Herida. Resistencia: 3.',
        'FIELD DOSSIER: High-lethality covert-operations asset. Combats in close quarters with his combat blade (Range 0, 2 dice, 3+ hit), eliminating walkers for free. In gameplay, he stands out with Limitless Stamina and Hand-to-Hand Expert. His Spawn Ability punishes enemy proximity: whenever a Rush! card is drawn, any Zombie Hero within Range 1 of him instantly suffers 1 Wound. Toughness: 3.'
    )
};

export const getHeroLoreEntry = (alias?: string): HeroLoreEntry | undefined => {
    if (!alias) return undefined;
    return HERO_LORE[normalizeHeroKey(alias)];
};
